CONTEXT_KEY = "ctx"


class TaskRunner:
    """Core task execution engine."""

    def __init__(self, name, max_retries=3):
        self.name = name
        self.max_retries = max_retries
        self._results = []

    def run_task(self, context):
        """Execute a task with the given context."""
        key = f"{CONTEXT_KEY}:{context}"
        self._results.append(key)
        return {"runner": self.name, "key": key, "input": context}

    def run_task_async(self, context):
        """Async variant — schedule for later execution."""
        return {"deferred": True, "input": context}

    def get_results(self):
        return list(self._results)

