from .core import TaskRunner
from .errors import TaskFlowError


class Worker:
    """Wraps a TaskRunner to add tracking."""

    def __init__(self, runner: TaskRunner, worker_name="default"):
        if not isinstance(runner, TaskRunner):
            raise TypeError(f"Expected TaskRunner, got {type(runner).__name__}")
        self._runner = runner
        self.worker_name = worker_name
        self.context_id = f"worker-{worker_name}"

    def process(self, context):
        """Process a task through the runner."""
        result = self._runner.run_task(context)
        return {"worker": self.worker_name, "context_id": self.context_id, "result": result}

