from .core import TaskRunner


class Scheduler:
    """Schedules tasks across multiple runners."""

    def __init__(self):
        self._runners = []
        self.task_context = "default"

    def register(self, runner: TaskRunner):
        """Register a TaskRunner with the scheduler."""
        self._runners.append(runner)

    def dispatch(self, context):
        """Dispatch a task to all registered runners."""
        results = []
        for runner in self._runners:
            result = runner.run_task(context)
            result["task_context"] = self.task_context
            results.append(result)
        return results

    def count(self):
        return len(self._runners)

