class TaskQueue:
    """Queues tasks for batch execution."""

    def __init__(self, runner):
        self._runner = runner
        self._pending = []
        self.context_data = {}

    def enqueue(self, context):
        """Add a task context to the queue."""
        self._pending.append(context)

    def flush(self):
        """Execute all queued tasks."""
        results = []
        for context in self._pending:
            result = self._runner.run_task(context)
            result["context_data"] = self.context_data
            results.append(result)
        self._pending.clear()
        return results

