from .core import TaskRunner


class Pipeline:
    """Chains multiple TaskRunners in sequence."""

    def __init__(self, name="pipeline"):
        self.name = name
        self._stages = []
        self.context_type = "sequential"

    def add_stage(self, runner: TaskRunner):
        """Add a TaskRunner as a pipeline stage."""
        self._stages.append(runner)

    def execute(self, context):
        """Run context through all pipeline stages."""
        current = context
        for stage in self._stages:
            result = stage.run_task(current)
            current = result["key"]
        return {"pipeline": self.name, "context_type": self.context_type, "final": current}

