class TaskLogger:
    """Logs task execution details."""

    def __init__(self, runner):
        self._runner = runner
        self.runner_id = f"log-{runner.name}"
        self.log = []

    def logged_run(self, context):
        """Execute a task and log the details."""
        context_data = {"input": context, "runner_id": self.runner_id}
        result = self._runner.run_task(context)
        entry = {"context_data": context_data, "result": result}
        self.log.append(entry)
        return result

