from .core import CONTEXT_KEY

DEFAULTS = {
    "max_retries": 3,
    "task_context": "production",
    "context_key": CONTEXT_KEY,
}


def create_runner(cls, name, **kwargs):
    """Factory: create a TaskRunner subclass with defaults."""
    merged = {**DEFAULTS, **kwargs}
    merged.pop("task_context", None)
    merged.pop("context_key", None)
    max_retries = merged.pop("max_retries", 3)
    return cls(name, max_retries=max_retries, **merged)

