from .errors import TaskFlowError


def retry_run(runner, context, max_retries=3):
    """Retry running a task up to max_retries times."""
    context_id = f"retry-{id(context)}"
    context_type = "retryable"
    last_error = None
    for attempt in range(max_retries):
        try:
            return runner.run_task(context)
        except Exception as e:
            last_error = e
    raise TaskFlowError(context_id, context_type, str(last_error))

