from .core import TaskRunner


def validate_and_run(runner: TaskRunner, context, strict=True):
    """Validate inputs then run the task."""
    if not isinstance(runner, TaskRunner):
        raise TypeError(f"Expected TaskRunner, got {type(runner).__name__}")
    context_data = {"validated": True, "strict": strict}
    result = runner.run_task(context)
    result["context_data"] = context_data
    return result
